import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import org.springframework.stereotype.Service;
import java.util.*;
import java.util.concurrent.ConcurrentHashMap;

@Service
public class ZerodhaInstrumentService {
    private final InstrumentFeedClient feedClient;
    // L0 in-memory cache for fallback (survives circuit open state):
    private final Map<String, InstrumentData> lastKnownData = new ConcurrentHashMap<>();

    ZerodhaInstrumentService(InstrumentFeedClient c) { feedClient = c; }

    @CircuitBreaker(
        name = "instrument-feed",
        fallbackMethod = "cachedInstrumentFallback"
    )
    public InstrumentData fetchInstrumentData(String symbol) {
        InstrumentData data = feedClient.fetch(symbol);
        lastKnownData.put(symbol, data);  // update cache on success
        return data;
    }

    private InstrumentData cachedInstrumentFallback(String symbol, Exception e) {
        InstrumentData cached = lastKnownData.get(symbol);
        if (cached != null) {
            System.out.printf("[CB Fallback] Returning STALE data for %s (feed down)%n", symbol);
            return cached.withStaleFlag(true);  // mark as potentially stale
        }
        System.out.printf("[CB Fallback] No cached data for %s — returning empty%n", symbol);
        return InstrumentData.empty(symbol);
    }

    // RISK of stale data:
    // Stock prices change every second during market hours.
    // A stale price from 2 minutes ago could cause:
    //   - Wrong P&L display
    //   - Incorrect margin calculations
    //   - Bad limit order placement
    // Mitigation: mark data as stale + short circuit wait time (10-15s)
    //             so service recovers quickly

    interface InstrumentFeedClient { InstrumentData fetch(String s); }
    record InstrumentData(String symbol, double price, boolean stale) {
        static InstrumentData empty(String s) { return new InstrumentData(s, 0, true); }
        InstrumentData withStaleFlag(boolean s) { return new InstrumentData(symbol, price, s); }
    }
}

