import io.github.resilience4j.circuitbreaker.*;
import org.springframework.scheduling.annotation.Scheduled;
import org.springframework.stereotype.Service;

@Service
public class CircuitBreakerMonitor {
    private final CircuitBreakerRegistry registry;

    CircuitBreakerMonitor(CircuitBreakerRegistry r) { registry = r; }

    public CircuitBreaker.State getState(String name) {
        return registry.circuitBreaker(name).getState();
        // Returns: CLOSED, OPEN, HALF_OPEN, DISABLED, FORCED_OPEN
    }

    public void logMetrics(String name) {
        CircuitBreaker cb = registry.circuitBreaker(name);
        CircuitBreaker.Metrics m = cb.getMetrics();
        System.out.printf(
            "[CB %s] state=%s failureRate=%.1f%% slowRate=%.1f%% calls=%d%n",
            name,
            cb.getState(),
            m.getFailureRate(),
            m.getSlowCallRate(),
            m.getNumberOfBufferedCalls()
        );
    }

    @Scheduled(fixedRate = 30_000)
    public void logAllStates() {
        registry.getAllCircuitBreakers().forEach(cb -> {
            CircuitBreaker.Metrics m = cb.getMetrics();
            System.out.printf(
                "[CB %s] state=%-12s failures=%.0f%% slow=%.0f%% buffered=%d%n",
                cb.getName(), cb.getState(),
                m.getFailureRate(), m.getSlowCallRate(),
                m.getNumberOfBufferedCalls()
            );
        });
    }

    // Check before call (optional — usually let annotation handle it):
    public boolean isCircuitOpen(String name) {
        return registry.circuitBreaker(name).getState() == CircuitBreaker.State.OPEN;
    }
}

