import io.github.resilience4j.circuitbreaker.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.beans.factory.annotation.Autowired;
import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.List;

@SpringBootTest
class CircuitBreakerTest {
    @Autowired BookMyShowEventService eventService;
    @MockBean BookMyShowEventService.SeatClient seatClient;
    @Autowired CircuitBreakerRegistry registry;

    @BeforeEach void resetCircuit() {
        // Reset circuit breaker to CLOSED state before each test:
        CircuitBreaker cb = registry.circuitBreaker("seat-service");
        cb.reset();
    }

    @Test
    void fallback_firesWhenCircuitOpens() {
        // Mock client to always fail:
        when(seatClient.getInteractiveMap(anyString()))
            .thenThrow(new RuntimeException("Seat service unavailable"));

        // First 5 calls: real exceptions recorded + fallback called
        for (int i = 0; i < 5; i++) {
            SeatMap result = eventService.getSeatMap("EVT-001");
            // Fallback returns zone pricing:
            assertEquals("ZONE", result.type(),
                "Should return zone pricing from fallback");
        }

        // Circuit should now be OPEN (5/5 = 100% failure ≥ 30% threshold):
        CircuitBreaker cb = registry.circuitBreaker("seat-service");
        assertEquals(CircuitBreaker.State.OPEN, cb.getState(),
            "Circuit should be OPEN after 5 failures");
    }

    @Test
    void fallback_returnsCorrectDefault() {
        when(seatClient.getInteractiveMap("EVT-999"))
            .thenThrow(new RuntimeException("Not found"));

        SeatMap result = eventService.getSeatMap("EVT-999");

        assertEquals("ZONE", result.type(), "Fallback should return ZONE pricing");
        assertEquals("EVT-999", result.eventId());
    }
}

