import io.github.resilience4j.circuitbreaker.*;
import org.springframework.stereotype.Service;
import jakarta.annotation.PostConstruct;
import java.util.concurrent.atomic.AtomicInteger;

@Service
public class CircuitBreakerEventListener {
    private final CircuitBreakerRegistry registry;
    public final AtomicInteger openEventCount = new AtomicInteger(0);

    CircuitBreakerEventListener(CircuitBreakerRegistry r) { registry = r; }

    @PostConstruct
    public void registerListeners() {
        // Register listener for ALL circuit breakers:
        registry.getAllCircuitBreakers().forEach(this::attachListener);

        // Also attach to any future-registered circuit breakers:
        registry.getEventPublisher()
            .onEntryAdded(event -> attachListener(event.getAddedEntry()));
    }

    private void attachListener(CircuitBreaker cb) {
        cb.getEventPublisher()
            .onStateTransition(event -> {
                CircuitBreaker.StateTransition transition = event.getStateTransition();
                String name = cb.getName();

                switch (transition) {
                    case CLOSED_TO_OPEN:
                        openEventCount.incrementAndGet();
                        System.err.printf(
                            "[ALERT CRITICAL] Circuit '%s' OPENED! " +
                            "Failure/slow rate exceeded threshold.%n", name);
                        // pagerDutyClient.createIncident(name, "CRITICAL");
                        break;
                    case OPEN_TO_HALF_OPEN:
                        System.out.printf(
                            "[INFO] Circuit '%s' testing recovery (HALF-OPEN)%n", name);
                        break;
                    case HALF_OPEN_TO_CLOSED:
                        System.out.printf(
                            "[INFO] Circuit '%s' RECOVERED (CLOSED)%n", name);
                        // pagerDutyClient.resolveIncident(name);
                        break;
                    case HALF_OPEN_TO_OPEN:
                        System.err.printf(
                            "[WARN] Circuit '%s' recovery FAILED — back to OPEN%n", name);
                        break;
                }
            });
    }
}

