import java.util.*;
import java.util.concurrent.*;

record ChargeRequest(String cardToken, double amount, String currency) {}
record ChargeResult(String id, String status, String errorCode) {}

@Service
class PaymentGatewayService {
    private final GatewayClient client;
    private final Queue<ChargeRequest> retryQueue = new ConcurrentLinkedQueue<>();

    PaymentGatewayService(GatewayClient c) { client=c; }

    @CircuitBreaker(name="payment-gateway", fallbackMethod="chargeFallback")
    public ChargeResult chargeCard(ChargeRequest req) {
        return client.charge(req);
    }

    private ChargeResult chargeFallback(ChargeRequest req, Exception e) {
        System.out.println("[CB] Payment gateway down — queuing " + req.cardToken());
        retryQueue.offer(req);
        return new ChargeResult("PENDING-" + UUID.randomUUID().toString().substring(0,8),
            "PENDING", "GATEWAY_UNAVAILABLE");
    }

    @CircuitBreaker(name="refund-gateway", fallbackMethod="refundFallback")
    public ChargeResult refundPayment(String paymentId) {
        return client.refund(paymentId);
    }

    private ChargeResult refundFallback(String paymentId, Exception e) {
        System.out.println("[CB] Refund gateway down for " + paymentId + " — queuing");
        return new ChargeResult(paymentId, "REFUND_QUEUED", null);
    }

    Queue<ChargeRequest> getRetryQueue() { return retryQueue; }

    interface GatewayClient {
        ChargeResult charge(ChargeRequest r);
        ChargeResult refund(String paymentId);
    }
}

@SpringBootTest
class PaymentGatewayServiceTest {
    @Autowired PaymentGatewayService svc;
    @MockBean PaymentGatewayService.GatewayClient client;
    @Autowired io.github.resilience4j.circuitbreaker.CircuitBreakerRegistry reg;

    @BeforeEach void reset() { reg.circuitBreaker("payment-gateway").reset(); }

    @Test void fallback_returnsPendingStatus() {
        when(client.charge(any())).thenThrow(new RuntimeException("Gateway timeout"));
        ChargeRequest req = new ChargeRequest("tok_visa_4242", 999.0, "INR");
        ChargeResult result = svc.chargeCard(req);
        assertEquals("PENDING", result.status());
    }

