import io.github.resilience4j.circuitbreaker.*;
import org.springframework.boot.actuate.health.*;
import org.springframework.stereotype.Component;

@Component("circuitBreakerOverallHealth")
public class CircuitBreakerHealthIndicator implements HealthIndicator {
    private final CircuitBreakerRegistry registry;

    CircuitBreakerHealthIndicator(CircuitBreakerRegistry r) { registry = r; }

    @Override
    public Health health() {
        boolean anyOpen = registry.getAllCircuitBreakers()
            .stream()
            .anyMatch(cb -> cb.getState() == CircuitBreaker.State.OPEN);

        if (anyOpen) {
            // List which circuits are open:
            var openCircuits = registry.getAllCircuitBreakers()
                .stream()
                .filter(cb -> cb.getState() == CircuitBreaker.State.OPEN)
                .map(cb -> cb.getName() + "=OPEN (" +
                    String.format("%.0f", cb.getMetrics().getFailureRate()) + "% failures)")
                .toList();
            return Health.down()
                .withDetail("openCircuits", openCircuits)
                .withDetail("message", "One or more dependencies unavailable")
                .build();
        }

        return Health.up()
            .withDetail("allCircuits", "CLOSED")
            .build();
    }

    // WHY THIS MATTERS FOR KUBERNETES:
    // Kubernetes readiness probe: GET /actuator/health
    // If health returns DOWN (circuit open = dependency down):
    //   Kubernetes removes this pod from load balancer rotation.
    //   Traffic routed to healthy pods that haven't opened circuits.
    //   THIS pod: no new traffic + existing circuits test recovery.
    //   When circuits CLOSE: health returns UP → Kubernetes adds back to rotation.
    // Result: automatic traffic routing away from degraded instances!

    public static void main(String[] a) {
        System.out.println("Circuit OPEN → Health DOWN → K8s removes pod from LB");
    }
}

