import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.beans.factory.annotation.Autowired;
import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;

record SwiggyOrder(String id, String restaurantId, double total) {}
record OrderResult(String orderId, String status, List<String> warnings) {}

@Service
class SwiggyOrderService {
    interface AddressValidator { void validate(String id); }
    interface RestaurantApi     { boolean isOpen(String rid); }
    interface DiscountEngine    { double apply(SwiggyOrder o); }
    interface RestaurantNotifier{ void notify(String id); }

    private final AddressValidator av;
    private final RestaurantApi ra;
    private final DiscountEngine de;
    private final RestaurantNotifier rn;
    private final List<String> retryQueue = new ArrayList<>();

    SwiggyOrderService(AddressValidator av,RestaurantApi ra,DiscountEngine de,RestaurantNotifier rn){
        this.av=av;this.ra=ra;this.de=de;this.rn=rn;
    }

    @CircuitBreaker(name="address-validator",fallbackMethod="skipAddressValidation")
    public void validateAddress(String orderId){ av.validate(orderId); }
    private void skipAddressValidation(String id,Exception e){
        System.out.println("[CB] Address validation skipped for "+id);
    }

    @CircuitBreaker(name="restaurant-api",fallbackMethod="assumeOpen")
    public boolean checkRestaurantAvailability(String rid){ return ra.isOpen(rid); }
    private boolean assumeOpen(String rid,Exception e){
        System.out.println("[CB] Restaurant API down — assuming open for "+rid);
        return true;
    }

    @CircuitBreaker(name="discount-engine",fallbackMethod="noDiscount")
    public double applyDiscounts(SwiggyOrder order){ return de.apply(order); }
    private double noDiscount(SwiggyOrder order,Exception e){
        System.out.println("[CB] Discount engine down — no discount");
        return 0.0;
    }

    @CircuitBreaker(name="notification",fallbackMethod="queueNotification")
    public void notifyRestaurant(String orderId){ rn.notify(orderId); }
    private void queueNotification(String id,Exception e){
        retryQueue.add(id);
        System.out.println("[CB] Notification queued for "+id);
    }

    public OrderResult placeOrder(SwiggyOrder order) {
        List<String> warnings = new ArrayList<>();
        validateAddress(order.id());
        boolean available = checkRestaurantAvailability(order.restaurantId());
        if (!available) warnings.add("availability_unconfirmed");
        double discount = applyDiscounts(order);
        if (discount == 0.0) warnings.add("discount_unavailable");
        notifyRestaurant(order.id());
        return new OrderResult(order.id(), "PLACED", warnings);
    }

    List<String> getRetryQueue() { return retryQueue; }
}

@SpringBootTest
class SwiggyOrderServiceTest {
    @Autowired SwiggyOrderService svc;
    @MockBean SwiggyOrderService.AddressValidator av;
    @MockBean SwiggyOrderService.RestaurantApi ra;
    @MockBean SwiggyOrderService.DiscountEngine de;
    @MockBean SwiggyOrderService.RestaurantNotifier rn;
    @Autowired io.github.resilience4j.circuitbreaker.CircuitBreakerRegistry reg;

    @BeforeEach void reset(){
        for(String n:List.of("address-validator","restaurant-api","discount-engine","notification"))
            reg.circuitBreaker(n).reset();
        svc.getRetryQueue().clear();
    }
    @Test void allServicesDown_orderStillPlaced(){
        doThrow(new RuntimeException("down")).when(av).validate(any());
        when(ra.isOpen(any())).thenThrow(new RuntimeException("down"));
        when(de.apply(any())).thenThrow(new RuntimeException("down"));
        doThrow(new RuntimeException("down")).when(rn).notify(any());
        SwiggyOrder o=new SwiggyOrder("O001","R001",499.0);
        OrderResult result=svc.placeOrder(o);
        assertEquals("PLACED",result.status(),"Order should be placed despite all services failing");
        assertFalse(result.warnings().isEmpty(),"Should have degradation warnings");
    }
    @Test void notificationFailed_queuedForRetry(){
        doThrow(new RuntimeException("notif down")).when(rn).notify(any());
        svc.placeOrder(new SwiggyOrder("O002","R001",299.0));
        assertTrue(svc.getRetryQueue().contains("O002"));
    }
