exercises.expected_solution:
# application.yml:
# resilience4j:
#   circuitbreaker:
#     instances:
#       inventory-count:
#         slidingWindowType: COUNT_BASED
#         slidingWindowSize: 10  # last 10 calls regardless of when
#         # Problem: 10 failures at 2am (low traffic) keep circuit open for 30s
#         # even though it's the middle of the night with no real traffic
#
#       inventory-availability:
#         slidingWindowType: TIME_BASED
#         slidingWindowSize: 30  # calls in the last 30 SECONDS
#         minimumNumberOfCalls: 5
#         # Better for variable traffic:
#         # During peak (500 calls/30s): 50% failures → opens quickly
#         # During off-peak (2 calls/30s): needs 5 calls minimum first
#
# WHEN TIME_BASED IS BETTER:
# - Variable traffic (spikes during dinner, quiet at night)
# - Want to track failures in a time period regardless of call volume
# - COUNT_BASED can open circuit on old failures from low-traffic periods
#
# WHAT HAPPENS DURING IDLE:
# COUNT_BASED: old failures stay in the window until replaced by new calls
#   → circuit may stay open based on stale historical failures
# TIME_BASED: failures older than the window duration drop off automatically
#   → circuit may close on its own when old failures age out (no minimumCalls met)

import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import org.springframework.stereotype.Service;
import java.util.*;

@Service
public class FlipkartInventoryService {
    private final InventoryClient client;
    FlipkartInventoryService(InventoryClient c) { client = c; }

    @CircuitBreaker(name = "inventory-availability", fallbackMethod = "inventoryFallback")
    public Integer getAvailableStock(String productId) {
        return client.fetchStock(productId);
    }

    private Integer inventoryFallback(String productId, Exception e) {
        System.out.println("[CB TIME_BASED] Inventory service down for " + productId);
        return null;  // unknown stock — UI shows 'Limited availability'
    }

    interface InventoryClient { Integer fetchStock(String id); }

    public static void main(String[] a) {
        System.out.println("TIME_BASED: tracks failures in last N seconds");
        System.out.println("COUNT_BASED: tracks last N calls regardless of time");
        System.out.println("During idle: TIME_BASED auto-ages; COUNT_BASED holds old failures");
    }
}

import io.github.resilience4j.circuitbreaker.annotation.CircuitBreaker;
import io.github.resilience4j.circuitbreaker.*;
import org.springframework.stereotype.*;
import org.springframework.boot.test.context.SpringBootTest;
import org.springframework.boot.test.mock.mockito.MockBean;
import org.springframework.beans.factory.annotation.Autowired;
import jakarta.annotation.PostConstruct;
import static org.mockito.Mockito.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;
import java.util.*;
import java.util.concurrent.atomic.*;

record BookingReq(String eventId,String seatId,String cardToken,String userId){}
record BookingRes(String bookingId,String status,List<String> warnings){}

@Service
class BMSBookingService {
    interface EventApi      { String getEventName(String id); }
    interface SeatService   { boolean reserveSeat(String id); }
    interface PaymentGw     { String charge(String token, double amt); }
    interface NotifService  { void notify(String userId, String msg); }

    private final EventApi ea; private final SeatService ss;
    private final PaymentGw pg; private final NotifService ns;
    private final List<String> notifQueue = new ArrayList<>();

    BMSBookingService(EventApi ea,SeatService ss,PaymentGw pg,NotifService ns){
        this.ea=ea;this.ss=ss;this.pg=pg;this.ns=ns;
    }

    @CircuitBreaker(name="event-api",fallbackMethod="unknownEvent")
    String getEventName(String id){ return ea.getEventName(id); }
    private String unknownEvent(String id,Exception e){ return "Concert (details unavailable)"; }

    @CircuitBreaker(name="seat-service",fallbackMethod="seatReservedOptimistically")
    boolean reserveSeat(String id){ return ss.reserveSeat(id); }
    private boolean seatReservedOptimistically(String id,Exception e){
        System.out.println("[CB] Seat service down — optimistic reserve for "+id);
        return true;
    }

    @CircuitBreaker(name="payment-gw",fallbackMethod="paymentFailed")
    String chargeCard(String token,double amt){ return pg.charge(token,amt); }
    private String paymentFailed(String token,double amt,Exception e){
        return "FAILED"; // payment is critical — must surface failure
    }

    @CircuitBreaker(name="notification",fallbackMethod="queueNotif")
    void notifyUser(String uid,String msg){ ns.notify(uid,msg); }
    private void queueNotif(String uid,String msg,Exception e){ notifQueue.add(uid+":"+msg); }

    public BookingRes book(BookingReq req){
        List<String> warn=new ArrayList<>();
        String event=getEventName(req.eventId());
        if(event.contains("unavailable")) warn.add("event_details_degraded");
        boolean seatOk=reserveSeat(req.seatId());
        if(!seatOk) return new BookingRes(null,"SEAT_UNAVAILABLE",warn);
        String payResult=chargeCard(req.cardToken(),500.0);
        if("FAILED".equals(payResult)) return new BookingRes(null,"PAYMENT_FAILED",warn);
        notifyUser(req.userId(),"Your ticket for "+event+" is confirmed!");
        return new BookingRes("BKG-"+System.currentTimeMillis(),"CONFIRMED",warn);
    }
    List<String> getNotifQueue(){ return notifQueue; }
}

@Service
class BMSCBAlerts {
    public final AtomicInteger openCount=new AtomicInteger(0);
    private final CircuitBreakerRegistry reg;
    BMSCBAlerts(CircuitBreakerRegistry r){reg=r;}
    @PostConstruct void listen(){
        reg.getAllCircuitBreakers().forEach(cb->cb.getEventPublisher()
            .onStateTransition(e->{
                if(e.getStateTransition()==CircuitBreaker.StateTransition.CLOSED_TO_OPEN){
                    openCount.incrementAndGet();
                    System.err.println("[ALERT] "+cb.getName()+" OPENED!");
                }
            }));
    }
}

@SpringBootTest
class BMSBookingTest {
    @Autowired BMSBookingService svc;
    @Autowired BMSCBAlerts alerts;
