    @Autowired CircuitBreakerRegistry reg;

    @BeforeEach void reset(){
        for(String n:List.of("event-api","seat-service","payment-gw","notification"))
            try{reg.circuitBreaker(n).reset();}catch(Exception ignore){}
        svc.getNotifQueue().clear();
    }
    @Test void booking_confirmedDespiteNonCriticalFailures(){
        when(ea.getEventName(any())).thenThrow(new RuntimeException("down"));
        when(ss.reserveSeat(any())).thenReturn(true);
